    /// A qualificação da evidência permite análises mais sofisticadas
    /// sobre o grafo de dependência, como detecção de código morto
    /// ou classificação da intensidade do acoplamento.
    /// </summary>
    public enum TipoReferencia
    {
        /// <summary>
        /// Menção simples do tipo no código.
        /// Exemplo:
        /// UserService service;
        /// </summary>
        Mention,

        /// <summary>
        /// Instanciação direta do tipo.
        /// Exemplo:
        /// new UserService();
        /// </summary>
        Instantiation,

        /// <summary>
        /// Chamada estática de método.
        /// Exemplo:
        /// UserService.DoSomething();
        /// </summary>
        StaticCall,

        /// <summary>
        /// Uso dentro de generics.
        /// Exemplo:
        /// List&lt;UserService&gt;
        /// </summary>
        Generic,

        /// <summary>
        /// Uso em typeof().
        /// Exemplo:
        /// typeof(UserService)
        /// </summary>
        Typeof,

        /// <summary>
        /// Uso em nameof().
        /// Exemplo:
        /// nameof(UserService)
        /// </summary>
        Nameof,

        /// <summary>
        /// Declaração de variável tipada.
        /// Exemplo:
        /// UserService service;
        /// </summary>
        Declaration
    }

